"""Report content - all chapter writing functions"""
import os, sys
sys.path.insert(0, os.path.dirname(__file__))
from generate_report import add_para, add_bullet, add_centered, add_chapter_heading, add_section_heading, add_subsection, make_table, add_figure

def write_chapter_01(doc):
    add_chapter_heading(doc, 1, "INTRODUCTION")
    add_para(doc, "In the contemporary landscape of software engineering and information technology, project management has established itself as one of the most critical disciplines governing the successful planning, execution, monitoring, and delivery of software products and services. The concept of project management encompasses a wide range of activities including task allocation, resource planning, timeline management, team coordination, risk assessment, and quality assurance. As organizations continue to embrace digital transformation strategies and adopt distributed work models, the demand for efficient, centralized, and web-based project management platforms has grown exponentially over the past decade. These platforms serve as the backbone of modern software development teams, enabling stakeholders at every level to maintain visibility into project progress, communicate effectively, and make data-driven decisions.", first_indent=1.27)
    add_para(doc, "The evolution of project management practices has undergone several significant phases over the years. In the early days of software development, project tracking was primarily conducted through manual processes including physical whiteboards, handwritten task lists, and face-to-face meetings. As computing technology advanced, teams transitioned to digital tools such as spreadsheets, shared documents, and email-based communication systems. While these tools provided some level of digital organization, they introduced new challenges including version conflicts, scattered information repositories, difficulty in tracking real-time progress, and limited scalability for growing teams. The emergence of dedicated project management software addressed some of these concerns, but many commercially available solutions impose substantial licensing costs, rigid workflow structures, and steep learning curves that hinder adoption, particularly among small teams, startups, and academic institutions.", first_indent=1.27)
    add_para(doc, "The rise of agile methodologies such as Scrum, Kanban, and Extreme Programming has further transformed the expectations placed on project management tools. Modern development teams require platforms that support iterative development cycles, sprint planning, backlog management, continuous integration workflows, and real-time collaboration across geographically distributed team members. Additionally, the increasing emphasis on cybersecurity and data protection necessitates that project management applications implement robust authentication mechanisms, granular authorization controls, and secure data transmission protocols to protect sensitive project information and user credentials from unauthorized access and potential security breaches.", first_indent=1.27)
    add_para(doc, "To address these multifaceted challenges, this project presents the design, development, and implementation of a comprehensive full-stack Project Management Application that provides a unified, web-based platform for managing projects, organizing tasks, coordinating team members, and tracking progress through an intuitive and visually appealing user interface. The application is built using industry-standard technologies including Java Spring Boot for the backend services and React for the frontend interface, ensuring scalability, security, maintainability, and a premium user experience.", first_indent=1.27)
    add_para(doc, "The backend of the application is developed using the Spring Boot framework, which is built on top of the Spring Framework and provides extensive support for rapid application development through auto-configuration, embedded server support, and a rich ecosystem of starter dependencies. The application follows a layered architecture pattern that clearly separates the presentation layer (REST controllers), business logic layer (service classes), and data access layer (repository interfaces). Spring Security is integrated to implement JWT-based stateless authentication, which eliminates the need for server-side session management and enables secure, scalable API communication. Spring Data JPA is used to abstract database operations, providing automatic implementation of common CRUD operations through repository interfaces that interact with an H2 relational database.", first_indent=1.27)
    add_para(doc, "The frontend of the application is developed using React 18, a popular JavaScript library maintained by Meta (formerly Facebook) for building dynamic, component-based user interfaces. React's virtual DOM mechanism ensures efficient rendering performance, while its hooks-based architecture simplifies state management and side effect handling within functional components. The application employs React Router for client-side navigation, React Context API for global authentication state management, and Axios as the HTTP client with request and response interceptors for automatic JWT token injection and error handling. The user interface is designed with a professional dark theme featuring glassmorphism effects, gradient accents, smooth CSS animations, and responsive layouts that adapt seamlessly across desktop, tablet, and mobile devices.", first_indent=1.27)
    add_para(doc, "The application implements a sophisticated dual-level role-based access control system that operates at both the system level and the project level. System-level roles including User, Manager, and Admin determine the overall administrative privileges of each user within the platform. Project-level roles including Owner, Admin, Mentor, Member, and Viewer control the specific permissions and access rights of users within individual projects. This multi-tier authorization model ensures that sensitive operations such as user management, role modifications, and project deletion are restricted to appropriately privileged users, while still providing flexibility for team leads to assign granular permissions within their project contexts.", first_indent=1.27)

def write_chapter_02(doc):
    add_chapter_heading(doc, 2, "LITERATURE SURVEY")
    add_para(doc, "A comprehensive literature survey was conducted to understand the existing research, tools, and methodologies in the domain of web-based project management systems, full-stack application development, RESTful API design, and modern authentication mechanisms. The following studies and works were reviewed to establish a strong theoretical foundation for the proposed system.", first_indent=1.27)
    
    add_section_heading(doc, "2.1", "Building RESTful Web Services with Spring Boot (Craig Walls, 2016)")
    add_para(doc, "This comprehensive study examines how the Spring Boot framework fundamentally simplifies the development of RESTful web services in Java. The author demonstrates that Spring Boot's convention-over-configuration approach reduces the amount of boilerplate code required by approximately seventy percent compared to traditional Spring applications. The framework provides embedded server support through Apache Tomcat, Jetty, or Undertow, eliminating the need for external application server deployment and configuration. Spring Boot Starters provide pre-configured dependency descriptors that automatically include all necessary libraries for specific functionalities such as web development, data access, security, and testing. The study shows how REST controllers annotated with @RestController can expose API endpoints that accept and return JSON data, enabling smooth communication between frontend and backend components of modern web applications. The auto-configuration mechanism analyzes the classpath dependencies and automatically configures beans, data sources, and other components with sensible defaults, allowing developers to focus primarily on implementing business logic rather than spending time on infrastructure setup.", first_indent=1.27)
    add_para(doc, "Disadvantages identified in this study include the requirement for developers to have a solid understanding of the broader Spring ecosystem, as Spring Boot abstracts many configuration details that may need to be customized for specific use cases. Additionally, improper API design patterns such as overly chatty interfaces, lack of pagination, or inefficient data serialization may lead to performance bottlenecks in production environments.", first_indent=1.27)

    add_section_heading(doc, "2.2", "Secure Web Applications Using Spring Security (Ben Alex, 2017)")
    add_para(doc, "This research provides an extensive analysis of implementing robust security mechanisms in Java web applications using the Spring Security framework. The study covers the complete authentication lifecycle including credential validation, session management, remember-me functionality, and multi-factor authentication. The authorization framework supports both URL-based access control through security filter chains and method-level security through annotations such as @PreAuthorize and @Secured. The paper explains how Spring Security's architecture is built around a series of servlet filters that intercept incoming HTTP requests and apply security rules before the request reaches the application controllers. The study demonstrates how custom authentication providers can be implemented to support various authentication strategies including form-based login, HTTP Basic authentication, OAuth 2.0, and token-based authentication using JSON Web Tokens. The integration of password encoding algorithms such as BCrypt, SCrypt, and Argon2 ensures that user credentials are stored securely in the database, making it computationally infeasible for attackers to recover original passwords even if the database is compromised.", first_indent=1.27)

    add_section_heading(doc, "2.3", "Database Management Using JPA and Hibernate (Gavin King, 2018)")
    add_para(doc, "This foundational study discusses how the Java Persistence API and Hibernate ORM framework together provide a powerful abstraction layer for database operations in Java applications. JPA defines a standard specification for object-relational mapping, allowing developers to interact with relational databases using Java objects and annotations rather than writing complex SQL queries. Hibernate serves as the reference implementation of JPA and provides additional features such as caching strategies, lazy loading of associations, batch processing, and query optimization. The study explains how entity classes annotated with @Entity, @Table, @Column, and relationship annotations such as @OneToMany, @ManyToOne, and @ManyToMany allow developers to define the database schema directly in Java code. Spring Data JPA further simplifies the data access layer by providing repository interfaces that automatically generate implementation classes based on method naming conventions, eliminating the need for boilerplate DAO code.", first_indent=1.27)

    add_section_heading(doc, "2.4", "Modern Frontend Development with React (Alex Banks, Eve Porcello, 2020)")
    add_para(doc, "This comprehensive study explores the React library and its ecosystem for building modern, dynamic user interfaces. React 18 introduces several significant improvements including concurrent rendering, automatic batching of state updates, and the Suspense API for handling asynchronous data loading. The component-based architecture promotes code reusability by encapsulating UI logic, state, and rendering within self-contained components that can be composed to build complex interfaces. The virtual DOM mechanism minimizes expensive direct DOM manipulations by maintaining an in-memory representation of the UI and performing efficient diff calculations to determine the minimal set of changes needed. React Hooks including useState, useEffect, useContext, useCallback, and useMemo provide a clean, functional approach to managing component state, side effects, and performance optimization without relying on class-based component patterns.", first_indent=1.27)

    add_section_heading(doc, "2.5", "JWT-Based Stateless Authentication (Michael Jones et al., 2015)")
    add_para(doc, "This seminal work defines the JSON Web Token standard as specified in RFC 7519 for creating compact, URL-safe tokens that represent claims between two parties. JWT tokens consist of three components: a header specifying the signing algorithm, a payload containing encoded claims such as subject, issuer, expiration, and custom data, and a signature generated using HMAC-SHA256 or RSA algorithms. The stateless nature of JWT tokens eliminates the need for server-side session storage, making them particularly well-suited for horizontally scaled microservice architectures where requests may be handled by different server instances. The study discusses security considerations including token expiration policies, refresh token mechanisms, token revocation strategies, and protection against common attacks such as token theft, replay attacks, and cross-site scripting vulnerabilities.", first_indent=1.27)

    add_section_heading(doc, "2.6", "Role-Based Access Control Models (David Ferraiolo, NIST, 2001)")
    add_para(doc, "This foundational study from the National Institute of Standards and Technology presents the formal model for Role-Based Access Control systems. The RBAC model defines four components: users, roles, permissions, and sessions. Users are assigned to roles, and roles are granted permissions to perform specific operations on protected resources. The study describes three levels of RBAC: Core RBAC establishing the fundamental user-role-permission relationships, Hierarchical RBAC introducing role inheritance and senior-junior role relationships, and Constrained RBAC adding separation of duty policies and mutual exclusion constraints. RBAC models are widely adopted in enterprise applications because they simplify access management by allowing administrators to assign permissions to roles rather than individual users, reducing administrative overhead and improving security posture.", first_indent=1.27)

    add_section_heading(doc, "2.7", "Responsive Web Design Principles (Ethan Marcotte, 2011)")
    add_para(doc, "This pioneering work introduces the concept of responsive web design as an approach to creating web interfaces that adapt fluidly to different screen sizes and device capabilities. The three foundational pillars of responsive design include flexible grid layouts using relative units such as percentages and viewport units, flexible images that scale within containing elements, and CSS media queries that apply different styling rules based on device characteristics such as screen width, height, and orientation. The study demonstrates how a single codebase can deliver an optimal viewing experience across desktop monitors, tablets, and mobile phones without requiring separate implementations for each device type. Modern CSS features such as Flexbox, CSS Grid, and CSS custom properties have further enhanced the capabilities available to responsive web designers.", first_indent=1.27)

def write_chapter_03(doc):
    add_chapter_heading(doc, 3, "EXISTING SYSTEM")
    add_section_heading(doc, "3.1", "Existing System")
    add_para(doc, "The current landscape of project management in software development teams is dominated by a combination of manual processes and commercial software platforms. Many organizations, particularly small to medium-sized teams and academic institutions, continue to rely on general-purpose productivity tools for managing their project workflows. Spreadsheet applications such as Microsoft Excel and Google Sheets are frequently used to maintain task lists, track deadlines, and record progress updates. While spreadsheets offer flexibility in data organization, they were not designed for collaborative project management and present significant limitations when used for this purpose.", first_indent=1.27)
    add_para(doc, "Email-based communication remains one of the most common methods for coordinating project activities, distributing task assignments, and sharing status updates among team members. However, email threads quickly become unwieldy as project complexity increases, leading to scattered information, missed messages, and difficulty in maintaining a chronological record of decisions and action items. The lack of centralized visibility into project status means that team leads and managers must manually aggregate information from multiple sources to obtain an accurate picture of project progress.", first_indent=1.27)
    add_para(doc, "Commercially available project management platforms such as Jira, Asana, Trello, Monday.com, and Microsoft Project offer comprehensive features for task tracking, sprint planning, resource allocation, and team collaboration. These platforms provide sophisticated capabilities including Kanban boards, Gantt charts, burndown charts, time tracking, and integration with development tools such as GitHub, Slack, and CI/CD pipelines. However, these commercial solutions present several significant challenges for many organizations. The licensing costs of enterprise-grade project management tools can be substantial, often requiring per-user monthly subscriptions that become prohibitively expensive as team sizes grow. Additionally, many of these platforms impose rigid workflow structures that may not align with the specific processes and conventions adopted by individual teams.", first_indent=1.27)
    add_para(doc, "Some organizations have attempted to develop custom in-house project management solutions to address the limitations of both manual methods and commercial platforms. However, these custom solutions are frequently developed as monolithic applications without proper architectural patterns, lack comprehensive security implementations, and suffer from poor user interface design that limits adoption and usability. The absence of modern authentication mechanisms such as token-based security and the lack of granular role-based access control in many existing systems expose sensitive project data and user information to potential security risks.", first_indent=1.27)

    add_section_heading(doc, "3.2", "Drawbacks of Existing System")
    for d in [
        "Spreadsheet-based project tracking leads to version conflicts, data inconsistency, and difficulty in maintaining real-time visibility into project status across distributed team members.",
        "Email-based communication results in scattered information repositories, missed updates, difficulty in searching for specific decisions, and lack of structured task tracking capabilities.",
        "Commercial project management tools impose high licensing costs, steep learning curves, rigid workflow structures, and vendor lock-in that limits customization and data portability.",
        "Many existing custom solutions are built as monolithic applications without proper separation of concerns, making them difficult to maintain, test, extend, and scale as organizational needs evolve.",
        "Weak or outdated authentication mechanisms in legacy systems fail to adequately protect user credentials and sensitive project data from unauthorized access and security breaches.",
        "Limited or no granular role-based access control at the project level prevents teams from implementing fine-grained permission structures that reflect their organizational hierarchy.",
        "Poor integration between task management, team coordination, and progress visualization features forces users to switch between multiple tools, reducing productivity and increasing context-switching overhead.",
        "Lack of responsive design in many existing solutions limits accessibility on mobile devices and tablets, reducing the ability of team members to stay updated while away from their desks."
    ]:
        add_bullet(doc, d)

    add_section_heading(doc, "3.3", "Proposed System")
    add_para(doc, "The proposed system is a comprehensive full-stack Project Management Application specifically designed to overcome the limitations identified in existing project management approaches. The application provides a unified, web-based platform that integrates project creation, task organization, team member management, role-based access control, and real-time progress visualization within a single, cohesive system. The proposed solution is built using modern, open-source technologies including Java Spring Boot for the backend and React for the frontend, ensuring zero licensing costs while maintaining enterprise-grade quality, security, and performance standards.", first_indent=1.27)
    add_para(doc, "The system follows a clean, layered architecture pattern that separates the presentation layer, business logic layer, and data access layer into distinct components with well-defined interfaces. This architectural approach promotes code reusability, simplifies testing and debugging, and enables individual layers to be modified or replaced without affecting other parts of the system. JWT-based stateless authentication ensures secure API communication without the overhead of server-side session management, while the dual-level role-based access control system provides granular permission management at both the platform and project levels.", first_indent=1.27)

    add_section_heading(doc, "3.4", "Advantages of Proposed System")
    for a in [
        "Scalable three-tier architecture using Spring Boot and React with clear separation of concerns, enabling independent development, testing, and deployment of frontend and backend components.",
        "Secure JWT-based stateless authentication with BCrypt password hashing, token expiration policies, and automatic request filtering through Spring Security filter chains.",
        "Multi-tier role-based access control operating at both system level (User, Manager, Admin) and project level (Owner, Admin, Mentor, Member, Viewer) for fine-grained permission management.",
        "Comprehensive project lifecycle management supporting multiple project statuses including Active, On Hold, Completed, and Archived with automatic progress calculation.",
        "Complete task management system with priority levels, deadline tracking, assignee management, and status workflow progression from TODO through IN_PROGRESS, REVIEW, to DONE.",
        "Real-time dashboard with aggregated statistics, progress visualization, recent activity feeds, and personalized task overviews for quick decision-making.",
        "Professional, responsive dark-themed user interface with glassmorphism effects, smooth animations, and adaptive layouts that function across all device types.",
        "Built entirely with open-source technologies, eliminating licensing costs while providing enterprise-grade functionality, security, and performance."
    ]:
        add_bullet(doc, a)

def write_chapter_04(doc):
    add_chapter_heading(doc, 4, "PROPOSED SYSTEM")
    add_para(doc, "The proposed Project Management Application represents a carefully designed and thoroughly implemented full-stack web solution that addresses the core challenges identified during the analysis of existing project management approaches. This chapter provides a detailed description of the system's architecture, key features, design decisions, and the rationale behind the selection of specific technologies and patterns used throughout the development process.", first_indent=1.27)
    
    add_section_heading(doc, "4.1", "System Overview")
    add_para(doc, "The Project Management Application is designed as a client-server architecture where the React frontend communicates with the Spring Boot backend exclusively through RESTful API endpoints. This decoupled architecture allows the frontend and backend to be developed, tested, deployed, and scaled independently, which is a significant advantage for teams working on different aspects of the application simultaneously. The backend exposes over eighteen distinct API endpoints organized across five controller classes, each responsible for a specific functional domain including authentication, project management, task operations, user management, and administrative functions.", first_indent=1.27)
    add_para(doc, "The application's data model is centered around four core entities: Users, Projects, Tasks, and Project Members. These entities are mapped to corresponding database tables through JPA annotations and maintain well-defined relationships that enforce data integrity and support complex queries. The User entity serves as the foundation of the system's identity and access management layer, storing credentials, profile information, and system-level role assignments. The Project entity represents a managed unit of work containing metadata such as name, description, status, and ownership. The Task entity captures individual work items within projects, supporting attributes such as title, description, priority, status, deadline, and assignee. The ProjectMember entity implements the many-to-many relationship between Users and Projects, with an additional role attribute that defines the member's specific permissions within each project context.", first_indent=1.27)

    add_section_heading(doc, "4.2", "Technology Stack Selection")
    add_para(doc, "The selection of technologies for this project was guided by several key criteria including maturity and stability of the framework, strength of community support and documentation, compatibility with modern development practices, security capabilities, and long-term maintainability. The following technology stack was chosen after careful evaluation of available alternatives.", first_indent=1.27)

    make_table(doc, ["Component","Technology","Justification"], [
        ["Backend Framework","Spring Boot 3.2","Auto-configuration, embedded server, extensive ecosystem"],
        ["Programming Language","Java 21 (LTS)","Platform independence, strong typing, enterprise support"],
        ["Security","Spring Security + JWT","Comprehensive auth framework with stateless token support"],
        ["ORM / Data Access","Spring Data JPA","Repository pattern, auto-generated queries, transaction management"],
        ["Database","H2 (In-Memory)","Zero configuration, SQL console, ideal for development"],
        ["Frontend Library","React 18","Component architecture, virtual DOM, hooks, large ecosystem"],
        ["Build Tool","Vite","Fast HMR, optimized builds, ES module support"],
        ["HTTP Client","Axios","Interceptors, automatic JSON parsing, request cancellation"],
        ["Routing","React Router v6","Declarative routing, nested routes, protected route support"],
        ["Styling","Vanilla CSS","Full control, no dependencies, custom design system"],
        ["API Testing","Postman","GUI-based API testing, collection management, automation"],
    ])

    add_section_heading(doc, "4.3", "Security Architecture")
    add_para(doc, "Security is a foundational concern in the design of the Project Management Application. The system implements a comprehensive security architecture that addresses authentication, authorization, data protection, and secure communication. The authentication mechanism is built on JSON Web Tokens signed using the HMAC-SHA256 algorithm. When a user successfully authenticates by providing valid credentials, the server generates a JWT token containing the username as the subject claim, along with issued-at and expiration timestamps. This token is returned to the client and stored in the browser's localStorage for subsequent API requests.", first_indent=1.27)
    add_para(doc, "Every protected API request must include the JWT token in the Authorization header using the Bearer scheme. The JwtAuthenticationFilter, registered in the Spring Security filter chain, intercepts all incoming requests, extracts the token from the Authorization header, validates the token's signature and expiration, loads the corresponding user details, and sets the authentication context. If the token is invalid, expired, or missing for a protected endpoint, the filter returns an appropriate HTTP 401 Unauthorized response. The stateless nature of this approach means that the server does not maintain any session state between requests, which significantly improves scalability and reduces memory consumption.", first_indent=1.27)

def write_chapter_05(doc):
    add_chapter_heading(doc, 5, "SYSTEM REQUIREMENTS")
    add_para(doc, "System requirements define the necessary software tools, hardware components, and environmental configurations needed to successfully develop, deploy, and operate the Project Management Application. These requirements ensure that the application runs efficiently and provides optimal performance across different operating environments.", first_indent=1.27)

    add_section_heading(doc, "5.1", "Hardware Requirements")
    make_table(doc, ["Component","Specification"], [
        ["Processor","Intel Core i3 or higher (64-bit architecture)"],
        ["RAM","Minimum 4 GB (8 GB recommended for concurrent operation)"],
        ["Hard Disk","Minimum 20 GB free disk space"],
        ["Network","Stable internet connection for deployment and API communication"],
        ["Display","SVGA or higher resolution monitor"],
        ["Keyboard","Standard Windows keyboard"],
        ["Mouse","Two or three button mouse"],
    ])

    add_section_heading(doc, "5.2", "Software Requirements")
    make_table(doc, ["Component","Specification"], [
        ["Operating System","Windows 10 / Windows 11 / Linux / macOS"],
        ["Backend Language","Java (JDK 21 LTS or above)"],
        ["Backend Framework","Spring Boot 3.2.0"],
        ["Security Framework","Spring Security 6.x with JWT (JJWT Library)"],
        ["ORM Technology","Spring Data JPA with Hibernate"],
        ["Database","H2 In-Memory Database"],
        ["Frontend Library","React 18"],
        ["Frontend Build Tool","Vite 5.x"],
        ["HTTP Client","Axios 1.x"],
        ["Routing","React Router DOM 6.x"],
        ["IDE (Backend)","IntelliJ IDEA / Eclipse / VS Code"],
        ["IDE (Frontend)","Visual Studio Code"],
        ["API Testing","Postman"],
        ["Version Control","Git / GitHub"],
        ["Web Browser","Google Chrome / Mozilla Firefox / Microsoft Edge"],
    ])

    add_section_heading(doc, "5.3", "Software Features")
    add_subsection(doc, "5.3.1", "What is Java")
    add_para(doc, "Java is a high-level, class-based, object-oriented programming language that is designed to have as few implementation dependencies as possible. It was originally developed by James Gosling at Sun Microsystems and released in 1995 as a core component of Sun Microsystems' Java platform. Java is currently maintained by Oracle Corporation and is one of the most widely used programming languages in the world, particularly for enterprise-grade application development, Android mobile development, big data processing, and web service implementation.", first_indent=1.27)
    add_para(doc, "Java follows the principle of Write Once, Run Anywhere (WORA), meaning that compiled Java bytecode can run on any platform that supports the Java Virtual Machine without requiring recompilation. This platform independence, combined with strong memory management through automatic garbage collection, robust exception handling mechanisms, built-in multi-threading support, and comprehensive standard library, makes Java an ideal choice for developing scalable, secure, and maintainable backend services for web applications.", first_indent=1.27)
    add_para(doc, "Below are some key facts and features about Java that make it suitable for this project:", first_indent=1.27)
    for f in [
        "Java is platform-independent due to the Java Virtual Machine (JVM) which translates bytecode into machine-specific instructions at runtime.",
        "Java supports all four pillars of Object-Oriented Programming: Encapsulation, Inheritance, Polymorphism, and Abstraction.",
        "Java provides automatic memory management through garbage collection, eliminating manual memory allocation and deallocation.",
        "Java includes built-in support for multi-threaded programming, enabling concurrent task execution for improved performance.",
        "Java's strong type system and compile-time checking help catch errors early in the development process.",
        "Java has one of the largest and most active developer communities in the world, providing extensive libraries, frameworks, and support resources.",
        "Java is used by major technology companies including Google, Amazon, Netflix, LinkedIn, and Twitter for their backend systems and services."
    ]:
        add_bullet(doc, f)

    add_subsection(doc, "5.3.2", "Advantages of Java")
    for idx, adv in enumerate([
        ("Extensive Libraries", "Java provides a rich standard library (Java API) that includes thousands of classes and interfaces for performing common tasks such as data structure manipulation, file I/O, networking, database connectivity, security, and XML processing. Additionally, the Maven and Gradle build tools provide access to millions of third-party libraries through centralized repositories."),
        ("Platform Independence", "Java bytecode runs on any operating system that supports the JVM, including Windows, Linux, macOS, and various embedded systems. This eliminates the need to maintain separate codebases for different platforms."),
        ("Security", "Java provides a comprehensive security framework including the Security Manager, cryptographic APIs, SSL/TLS support, and bytecode verification. The JVM sandbox restricts untrusted code from performing dangerous operations."),
        ("Robust and Reliable", "Java's strong type checking, automatic memory management, exception handling, and lack of pointer arithmetic make it one of the most robust programming languages available for enterprise development."),
        ("Scalability", "Java applications can be scaled horizontally across multiple servers and containers, making them suitable for high-traffic web applications and microservice architectures."),
    ], 1):
        add_para(doc, f"{idx}. {adv[0]}", bold=True)
        add_para(doc, adv[1], first_indent=1.27)

    add_subsection(doc, "5.3.3", "What is Spring Boot")
    add_para(doc, "Spring Boot is an open-source Java-based framework developed by Pivotal Team (now VMware Tanzu) that simplifies the creation of production-ready applications built on the Spring Framework. Spring Boot takes an opinionated view of the Spring platform and third-party libraries, providing sensible default configurations that allow developers to get started with minimal setup. The framework was first released in 2014 and has since become the de facto standard for building enterprise Java applications, microservices, and RESTful web services.", first_indent=1.27)
    add_para(doc, "Spring Boot eliminates much of the boilerplate configuration traditionally required by Spring applications through its auto-configuration mechanism. By analyzing the classpath dependencies present in the application, Spring Boot automatically configures beans, data sources, security filters, and other components with appropriate default settings. Developers can override these defaults through application properties files or Java configuration classes when specific customizations are needed.", first_indent=1.27)
    add_para(doc, "Key features of Spring Boot that are utilized in this project include:", first_indent=1.27)
    for f in [
        "Auto-Configuration: Automatically configures Spring and third-party libraries based on the dependencies present in the classpath.",
        "Embedded Servers: Includes embedded Apache Tomcat, Jetty, or Undertow servers, eliminating the need for external application server deployment.",
        "Spring Boot Starters: Pre-configured dependency descriptors that bundle all required libraries for specific functionalities such as web, data, security, and testing.",
        "Spring Boot Actuator: Provides production-ready features for monitoring and managing the application, including health checks, metrics, and environment information.",
        "Spring Boot DevTools: Offers developer productivity features such as automatic application restart on code changes and live reload of web resources.",
    ]:
        add_bullet(doc, f)

    add_subsection(doc, "5.3.4", "What is React")
    add_para(doc, "React is an open-source JavaScript library for building user interfaces, developed and maintained by Meta (formerly Facebook) along with a community of individual developers and companies. React was first released in 2013 and has since become one of the most popular and widely adopted frontend libraries in the web development ecosystem. React is used by major organizations including Facebook, Instagram, Netflix, Airbnb, Uber, and Twitter for building their user-facing web applications.", first_indent=1.27)
    add_para(doc, "React follows a component-based architecture where the user interface is decomposed into small, self-contained, reusable components. Each component encapsulates its own structure (JSX), styling (CSS), and behavior (JavaScript logic), making it easy to develop, test, and maintain complex user interfaces. React 18, used in this project, introduces several significant improvements including concurrent rendering capabilities, automatic batching of state updates for improved performance, and the Suspense API for handling asynchronous data loading patterns.", first_indent=1.27)

def write_chapter_06(doc):
    add_chapter_heading(doc, 6, "METHODOLOGY")
    add_para(doc, "The methodology adopted for the development of the Project Management Application follows a structured, phase-wise approach that ensures systematic planning, implementation, testing, and deployment of the system. This chapter describes the development methodology, data flow through the system, and the various diagrams that illustrate the system's operational workflows and architectural structure.", first_indent=1.27)

    add_section_heading(doc, "6.1", "Development Methodology")
    add_para(doc, "The project follows an iterative development methodology that combines elements of the waterfall model for overall project planning with agile practices for implementation and testing. The development process is divided into five major phases: requirements analysis, system design, implementation, testing, and deployment. Each phase builds upon the outputs of the previous phase while allowing feedback loops that enable refinements and adjustments based on testing results and evolving requirements.", first_indent=1.27)
    add_para(doc, "During the requirements analysis phase, the functional and non-functional requirements of the system were identified through a comprehensive study of existing project management tools, user expectations, and industry best practices. The system design phase involved creating architectural blueprints, defining the database schema, designing the REST API structure, and planning the user interface layout. The implementation phase involved coding the backend services using Spring Boot and the frontend interface using React, following the architectural decisions made during the design phase. The testing phase included unit testing, integration testing, system testing, and user acceptance testing to verify the correctness and reliability of the application. Finally, the deployment phase involved configuring the application for production environments and deploying the backend to Render and the frontend to Vercel.", first_indent=1.27)

    add_section_heading(doc, "6.2", "Data Flow in the System")
    add_para(doc, "The data flow in the Project Management Application follows a well-defined path from the user interface to the database and back. Understanding this data flow is essential for comprehending how the system processes user requests and generates responses. The following description outlines the complete data flow for a typical user operation.", first_indent=1.27)
    add_para(doc, "When a user interacts with the React frontend by performing an action such as creating a new project, the React component triggers an API call using the Axios HTTP client. The Axios request interceptor automatically attaches the JWT authentication token to the request header. The request travels over the network to the Spring Boot backend, where it is first intercepted by the Spring Security filter chain. The JwtAuthenticationFilter extracts and validates the JWT token, and if the token is valid, the request proceeds to the appropriate REST controller.", first_indent=1.27)
    add_para(doc, "The REST controller receives the request, extracts the request body and path parameters, and delegates the processing to the corresponding service class. The service class contains the business logic for the operation, performing validations, applying business rules, and coordinating with the repository layer for data persistence. The repository interface, powered by Spring Data JPA, translates the service request into SQL queries that are executed against the H2 database. The database processes the query and returns the result to the repository, which maps the database records back to Java entity objects.", first_indent=1.27)
    add_para(doc, "The service class receives the entity objects, applies any necessary transformations or calculations such as computing task completion percentages, and returns a response object to the controller. The controller wraps the response in an appropriate HTTP response with the correct status code and returns it to the client. The Axios response interceptor on the frontend processes the response, and the React component updates its state with the new data, triggering a re-render of the user interface to reflect the changes.", first_indent=1.27)

    add_section_heading(doc, "6.3", "Data Flow Diagram")
    add_para(doc, "A Data Flow Diagram (DFD) is a graphical representation that depicts the flow of data through an information system. DFDs help visualize how data enters the system, how it is transformed through various processes, and where the processed data is stored or output. Two levels of DFDs are presented for the Project Management Application.", first_indent=1.27)

    add_subsection(doc, "6.3.1", "Level 0 DFD (Context Diagram)")
    add_para(doc, "The Level 0 DFD, also known as the Context Diagram, provides a high-level overview of the entire system showing the system as a single process interacting with external entities. The external entities include the User, Manager, and Admin actors. The User provides inputs such as registration credentials, login credentials, project details, and task information to the system. The system processes these inputs and returns outputs such as JWT authentication tokens, project lists, task boards, dashboard statistics, and progress reports. The Manager and Admin actors have additional interactions related to user management, role assignments, and system administration.", first_indent=1.27)
    add_figure(doc, 'dfd_level0.jpg', 'Data Flow Diagram \u2013 Level 0 (Context Diagram)', 1)

    add_subsection(doc, "6.3.2", "Level 1 DFD")
    add_para(doc, "The Level 1 DFD decomposes the single process from the Level 0 DFD into multiple sub-processes that represent the major functional modules of the system. The five primary processes identified are: Authentication Process which handles user login and registration, Project Management Process which manages project CRUD operations, Task Management Process which handles task creation, assignment, and status updates, Member Management Process which manages project team membership and roles, and Admin Process which handles administrative functions such as user management and role changes. Each process interacts with one or more data stores including the Users Store, Projects Store, Tasks Store, and Project Members Store. Data flows between processes indicate how information is shared and transformed across different functional modules.", first_indent=1.27)
    add_figure(doc, 'dfd_level1.jpg', 'Data Flow Diagram \u2013 Level 1', 2)

    add_section_heading(doc, "6.4", "Flow Charts")
    add_subsection(doc, "6.4.1", "Flow Chart: User Operations")
    add_para(doc, "The User Operations flow chart illustrates the step-by-step process that a regular user follows when interacting with the system. The flow begins at the Start node and proceeds to the Login or Register decision point. If the user is new, the registration process collects username, email, full name, and password, validates the input fields, creates the user account, and returns a JWT token. If the user is existing, the login process validates credentials against the database and returns a JWT token on success or an error message on failure.", first_indent=1.27)
    add_para(doc, "After successful authentication, the user is directed to the Dashboard which displays aggregated project and task statistics. From the Dashboard, the user can navigate to the Projects module to create new projects, view existing projects, or manage project details. Within a project, the user can access the Task Board to create tasks, update task statuses, assign tasks to team members, and set priorities and deadlines. The flow chart includes decision points for authorization checks, ensuring that users can only perform operations permitted by their assigned roles.", first_indent=1.27)

    add_subsection(doc, "6.4.2", "Flow Chart: Admin Operations")
    add_para(doc, "The Admin Operations flow chart depicts the administrative workflows available to users with Manager or Admin system roles. After authentication and dashboard access, admin users can navigate to the Admin Dashboard which provides two primary functional areas: User Management and Project Management. In the User Management section, admins can view all registered users, edit user details such as username, email, and password, change system roles between User, Manager, and Admin, and manage user accounts. In the Project Management section, admins can view all projects across the platform, monitor project progress and member counts, and perform bulk user assignments to projects with specific role assignments.", first_indent=1.27)

    add_section_heading(doc, "6.5", "System Architecture Diagram")
    add_para(doc, "The System Architecture Diagram provides a comprehensive view of the application's three-tier architecture showing the clear separation between the Client Tier (React Frontend), the Server Tier (Spring Boot Backend), and the Data Tier (H2 Database). The Client Tier contains the React components, React Router for navigation, Context API for state management, and Axios for HTTP communication. The Server Tier contains the Security Filter Chain, REST Controllers, Service Classes, and Repository Interfaces organized in the layered architecture pattern. The Data Tier contains the H2 database with tables for Users, Projects, Tasks, and Project Members. Communication between the Client and Server tiers occurs through HTTPS REST API calls with JWT Bearer token authentication. Communication between the Server and Data tiers occurs through JPA/JDBC connections.", first_indent=1.27)
    add_figure(doc, 'system_architecture.jpg', 'System Architecture Diagram', 3)

    add_section_heading(doc, "6.6", "UML Diagrams")
    add_subsection(doc, "6.6.1", "Class Diagram")
    add_para(doc, "The UML Class Diagram represents the static structure of the application by showing the main entity classes, their attributes, methods, and relationships. The four primary classes are User, Project, Task, and ProjectMember. The User class contains attributes including id (Long), username (String), email (String), password (String), fullName (String), systemRole (SystemRole enum), and createdAt (Timestamp). The Project class contains id, name, description, status (ProjectStatus enum), owner (User reference), createdAt, and updatedAt. The Task class contains id, title, description, status (TaskStatus enum), priority (TaskPriority enum), deadline (Date), project (Project reference), assignee (User reference), and createdAt. The ProjectMember class contains id, project (Project reference), user (User reference), role (MemberRole enum), and joinedAt. Relationships include User 1-to-many Project (ownership), Project 1-to-many Task, User 1-to-many Task (assignment), Project 1-to-many ProjectMember, and User 1-to-many ProjectMember.", first_indent=1.27)
    add_figure(doc, 'class_diagram.jpg', 'UML Class Diagram (Entity Relationships)', 5)

    add_subsection(doc, "6.6.2", "Use Case Diagram")
    add_para(doc, "The Use Case Diagram illustrates the functional requirements of the system by showing the interactions between three actor types (User, Manager, Admin) and the system's use cases. User actors can perform use cases including Register Account, Login/Logout, Create Project, View Projects, Edit/Delete Project, Create Task, Assign Task, Update Task Status, and View Dashboard. Manager actors inherit all User use cases and additionally can access the Admin Dashboard with User Management capabilities. Admin actors inherit all Manager use cases and additionally can Change User Roles and perform Bulk Project Assignments. The diagram uses standard UML notation with stick figures for actors, ovals for use cases, and a system boundary rectangle enclosing all use cases.", first_indent=1.27)
    add_figure(doc, 'use_case_diagram.jpg', 'UML Use Case Diagram', 4)

    add_subsection(doc, "6.6.3", "Sequence Diagram")
    add_para(doc, "The Sequence Diagram depicts the time-ordered interactions between system components for the authentication and project creation workflows. The diagram shows five lifelines: Client (React), AuthController, AuthService, JwtTokenProvider, and Database. For the login sequence, the Client sends a POST request with credentials to the AuthController, which delegates to AuthService for credential validation. AuthService queries the Database for the user record, verifies the password using BCrypt, and requests a JWT token from JwtTokenProvider. The generated token is returned through the call chain back to the Client. For the project creation sequence, the Client sends a POST request with the JWT token, which is validated by the Security Filter before reaching the ProjectController. The controller delegates to ProjectService for business logic execution, which persists the project through the Repository to the Database.", first_indent=1.27)
    add_figure(doc, 'sequence_diagram.jpg', 'UML Sequence Diagram (Authentication and Project Creation)', 6)

def write_chapter_07(doc):
    add_chapter_heading(doc, 7, "MODULES USED")
    add_para(doc, "The Project Management Application is organized into seven distinct functional modules, each responsible for a specific domain of system operations. This modular approach promotes code organization, separation of concerns, independent testability, and ease of maintenance. Each module encapsulates its own controllers, services, and data access components while interacting with other modules through well-defined interfaces.", first_indent=1.27)

    add_section_heading(doc, "7.1", "User Authentication and Registration Module")
    add_para(doc, "The User Authentication and Registration Module serves as the entry point for all users accessing the Project Management Application. This module is responsible for securely managing the complete user identity lifecycle including account creation, credential validation, token generation, and session management. The module ensures that only authenticated users can access the protected features of the application, which is a fundamental requirement for maintaining the security and integrity of project data.", first_indent=1.27)
    add_para(doc, "The registration process collects the user's desired username, email address, full name, and password. The system validates that the username and email are unique across the platform, verifies that the password meets the minimum security requirements including length, character diversity, and strength criteria, and then creates the user account by encoding the password using the BCrypt hashing algorithm before storing it in the database. Upon successful registration, a JWT token is generated and returned to the client, allowing the user to immediately access the application without requiring a separate login step.", first_indent=1.27)
    add_para(doc, "The login process accepts the user's username and password, retrieves the corresponding user record from the database, and verifies the provided password against the stored BCrypt hash using the matches method of the BCryptPasswordEncoder. If the credentials are valid, a JWT token is generated containing the username as the subject claim with a 24-hour expiration period. The token is signed using the HMAC-SHA256 algorithm with a server-side secret key, ensuring that the token cannot be forged or tampered with by malicious actors. The generated token is returned to the client along with user profile information including the username, email, full name, and system role.", first_indent=1.27)

    add_section_heading(doc, "7.2", "Project Management Module")
    add_para(doc, "The Project Management Module handles all operations related to creating, viewing, updating, and deleting projects within the system. This module provides the core project lifecycle management capabilities that enable teams to organize their work into discrete, manageable units. Each project contains metadata including a name, description, and status that together provide a comprehensive overview of the project's purpose and current state.", first_indent=1.27)
    add_para(doc, "When a new project is created, the system automatically assigns the creating user as the project owner by creating a corresponding ProjectMember record with the OWNER role. This ensures that every project has at least one member with full administrative privileges from the moment of creation. The project status can be set to one of four values: ACTIVE for projects currently in progress, ON_HOLD for projects that are temporarily paused, COMPLETED for projects that have finished all planned work, and ARCHIVED for projects that are retained for historical reference but are no longer actively managed.", first_indent=1.27)
    add_para(doc, "The module calculates derived metrics for each project including the total number of tasks, the number of completed tasks, and the completion percentage. These metrics are computed dynamically from the associated task records and included in the project response data, providing project managers with real-time visibility into project progress without requiring manual status updates.", first_indent=1.27)

    add_section_heading(doc, "7.3", "Task Management Module")
    add_para(doc, "The Task Management Module provides comprehensive capabilities for creating, organizing, assigning, and tracking individual work items within projects. Tasks represent the fundamental units of work that team members execute to advance project objectives. Each task captures essential information including a title, description, priority level, status, deadline, and assignee that together define the scope, urgency, timeline, and responsibility for the work item.", first_indent=1.27)
    add_para(doc, "The task status follows a defined workflow progression: TODO represents newly created tasks that have not yet been started, IN_PROGRESS indicates tasks that are actively being worked on, REVIEW marks tasks that have been completed and are awaiting review or approval, and DONE represents tasks that have been fully completed and accepted. This four-stage workflow mirrors common agile development practices and provides clear visibility into the progress of individual work items.", first_indent=1.27)
    add_para(doc, "Task priorities are categorized into four levels: LOW for routine tasks with flexible timelines, MEDIUM for standard tasks with normal urgency, HIGH for important tasks that require prompt attention, and URGENT for critical tasks that demand immediate action. The priority system helps team members and managers quickly identify which tasks require the most attention and allocate their efforts accordingly.", first_indent=1.27)

    add_section_heading(doc, "7.4", "Team Member Management Module")
    add_para(doc, "The Team Member Management Module manages the associations between users and projects through a membership system that supports granular, role-based permissions. This module enables project owners and administrators to build their project teams by adding registered users as project members with specific roles that define their access level and permitted operations within the project context.", first_indent=1.27)
    add_para(doc, "The module supports five project-level roles with hierarchical permissions: OWNER has full control over all project operations including deletion and member management, ADMIN can manage members and tasks but cannot delete the project, MENTOR can create and assign tasks and provide guidance, MEMBER can view project details and update assigned tasks, and VIEWER has read-only access to project information. This granular role system allows project leads to customize team structures that reflect their organizational hierarchies and workflow requirements.", first_indent=1.27)

    add_section_heading(doc, "7.5", "Dashboard and Analytics Module")
    add_para(doc, "The Dashboard and Analytics Module provides users with a centralized overview of their projects, tasks, and productivity metrics through an intuitive, visually rich interface. The dashboard serves as the landing page after authentication and is designed to give users an immediate understanding of their current workload, project status, and pending tasks without requiring navigation to individual project or task pages.", first_indent=1.27)
    add_para(doc, "The dashboard displays aggregated statistics including the total number of projects the user is associated with, the total number of tasks across all projects, the number of tasks in each status category, and the overall task completion percentage. Recent projects are listed with their names, statuses, and progress indicators, allowing quick navigation to frequently accessed projects. Personal task assignments are displayed with priority indicators and deadline information, helping users identify their most urgent action items.", first_indent=1.27)

    add_section_heading(doc, "7.6", "Admin Dashboard Module")
    add_para(doc, "The Admin Dashboard Module provides system-level administrative capabilities that are restricted to users with Manager or Admin system roles. This module enables administrators to manage all registered users, modify user credentials and roles, view all projects across the platform, and perform bulk user-to-project assignments. The module is accessible through a dedicated Admin link in the navigation sidebar that is only visible to users with appropriate system-level privileges.", first_indent=1.27)
    add_para(doc, "The User Management section displays a comprehensive table of all registered users with columns for username, email, full name, system role, and registration date. Each user row includes action buttons for editing user details and changing system roles. The role change feature allows administrators to promote or demote users between the User, Manager, and Admin roles, which immediately affects the user's access to administrative features across the platform.", first_indent=1.27)

    add_section_heading(doc, "7.7", "Security and Authorization Module")
    add_para(doc, "The Security and Authorization Module enforces authentication, authorization, and data protection policies across all system operations. This module implements a comprehensive security architecture built on Spring Security and JWT tokens that ensures only authenticated users can access protected resources and only authorized users can perform specific operations based on their assigned roles.", first_indent=1.27)
    add_para(doc, "The module configures the Spring Security filter chain to intercept all incoming HTTP requests and apply security rules before the requests reach the application controllers. Public endpoints such as login and registration are explicitly permitted without authentication, while all other endpoints require a valid JWT token. The JwtAuthenticationFilter, a custom OncePerRequestFilter implementation, extracts the JWT token from the Authorization header, validates the token signature and expiration using the JwtTokenProvider utility class, loads the corresponding UserDetails from the database, and sets the SecurityContext with the authenticated user information.", first_indent=1.27)

def write_chapter_08(doc):
    add_chapter_heading(doc, 8, "JAVA AND SPRING BOOT FUNDAMENTALS")
    add_para(doc, "This chapter provides a detailed exploration of the fundamental concepts, principles, and features of Java programming and the Spring Boot framework that form the technological foundation of the Project Management Application. Understanding these fundamentals is essential for comprehending the architectural decisions, design patterns, and implementation strategies employed throughout the project development.", first_indent=1.27)

    add_section_heading(doc, "8.1", "Java Programming Language")
    add_para(doc, "Java is a general-purpose, class-based, object-oriented programming language that was designed with the philosophy of minimizing implementation dependencies. Initially developed by James Gosling at Sun Microsystems in the early 1990s, Java was officially released to the public in 1995 and has since become one of the most influential and widely adopted programming languages in the history of computing. Java is currently maintained and developed by Oracle Corporation, with new versions released on a regular six-month cadence.", first_indent=1.27)
    add_para(doc, "The fundamental design principle behind Java is the concept of Write Once, Run Anywhere (WORA), which enables Java programs compiled into platform-independent bytecode to execute on any system that supports the Java Virtual Machine. The JVM acts as an abstraction layer between the Java application and the underlying operating system, translating bytecode into native machine instructions at runtime through either interpretation or Just-In-Time compilation. This platform independence has been a key factor in Java's widespread adoption for enterprise applications, web services, Android mobile development, and embedded systems.", first_indent=1.27)

    add_section_heading(doc, "8.2", "Object-Oriented Programming in Java")
    add_para(doc, "Object-Oriented Programming is the core programming paradigm used in Java, and all code in the Project Management Application is structured around OOP principles. OOP organizes software design around objects that combine data (attributes) and behavior (methods) into cohesive units, providing a natural way to model real-world entities and their interactions within software systems.", first_indent=1.27)

    add_subsection(doc, "8.2.1", "Classes and Objects")
    add_para(doc, "A class in Java serves as a blueprint or template that defines the properties and behaviors common to all objects of a certain type. In the Project Management Application, the entity classes User, Project, Task, and ProjectMember are defined as Java classes annotated with JPA annotations that map them to corresponding database tables. Each class defines private fields for storing data, public getter and setter methods for accessing and modifying the data, and constructors for creating new instances.", first_indent=1.27)

    add_subsection(doc, "8.2.2", "Encapsulation")
    add_para(doc, "Encapsulation is the mechanism of bundling data and the methods that operate on that data within a single unit while restricting direct access to some of the object's components. In Java, encapsulation is achieved through access modifiers: private fields prevent direct external access to an object's internal state, while public getter and setter methods provide controlled access pathways. In the Project Management Application, all entity fields are declared private and accessed through corresponding getter and setter methods generated by the Lombok library's @Data annotation, ensuring that data integrity is maintained throughout the application.", first_indent=1.27)

    add_subsection(doc, "8.2.3", "Inheritance")
    add_para(doc, "Inheritance allows a new class to acquire properties and behaviors from an existing class, establishing an is-a relationship between the parent and child classes. Java supports single inheritance through the extends keyword and interface implementation through the implements keyword. In the Project Management Application, Spring Boot's framework extensively uses inheritance; for example, the JwtAuthenticationFilter extends OncePerRequestFilter, and custom repository interfaces extend JpaRepository to inherit built-in CRUD operations.", first_indent=1.27)

    add_subsection(doc, "8.2.4", "Polymorphism")
    add_para(doc, "Polymorphism enables objects of different types to be treated through a common interface, with the actual behavior determined at runtime. Java supports two forms of polymorphism: compile-time polymorphism through method overloading and runtime polymorphism through method overriding. In the service layer of the application, polymorphism allows different service implementations to provide specialized behavior while conforming to a common interface contract.", first_indent=1.27)

    add_subsection(doc, "8.2.5", "Abstraction")
    add_para(doc, "Abstraction hides complex implementation details behind simplified interfaces, allowing developers to focus on what an object does rather than how it accomplishes its tasks. In the Project Management Application, the repository interfaces exemplify abstraction by defining method signatures for database operations such as findByUsername or findByProjectId without specifying the actual SQL queries or database interaction code. Spring Data JPA automatically generates the implementation based on the method names, providing a clean abstraction over the underlying data access complexity.", first_indent=1.27)

    add_section_heading(doc, "8.3", "Java Collections Framework")
    add_para(doc, "The Java Collections Framework provides a unified architecture for representing and manipulating groups of objects. Collections are extensively used throughout the Project Management Application for managing lists of projects, tasks, members, and other data sets. The framework includes interfaces such as List, Set, and Map, along with implementation classes such as ArrayList, HashSet, LinkedList, HashMap, and TreeMap. ArrayList is the most commonly used collection in the project for storing ordered lists of entities retrieved from the database. HashMap is used for key-value pair storage in configuration and response mapping. The Collections utility class provides algorithms for sorting, searching, and transforming collection contents.", first_indent=1.27)

    add_section_heading(doc, "8.4", "Spring Boot Architecture")
    add_para(doc, "Spring Boot's architecture builds upon the Spring Framework's Inversion of Control (IoC) container and Dependency Injection (DI) pattern. The IoC container manages the lifecycle of application objects (known as beans) and their dependencies, allowing developers to define components through annotations such as @Component, @Service, @Repository, and @Controller. When the application starts, Spring Boot's auto-configuration scans the classpath, creates bean instances, and injects dependencies automatically based on type matching and qualifier annotations.", first_indent=1.27)
    add_para(doc, "The layered architecture of the Spring Boot application in this project consists of the Controller layer handling HTTP request mapping and response formatting, the Service layer implementing business logic and transaction management, and the Repository layer managing database persistence operations. Each layer communicates with adjacent layers through dependency injection, creating a loosely coupled architecture where individual layers can be tested, modified, or replaced independently.", first_indent=1.27)

    add_section_heading(doc, "8.5", "REST API Development in Spring Boot")
    add_para(doc, "RESTful API development in Spring Boot leverages the Spring Web MVC framework with specialized annotations for defining endpoints, handling requests, and formatting responses. The @RestController annotation combines @Controller and @ResponseBody to indicate that a class handles REST API requests and automatically serializes return values to JSON. Method-level annotations including @GetMapping, @PostMapping, @PutMapping, @PatchMapping, and @DeleteMapping map HTTP methods to Java methods. Path variables, request parameters, and request body data are extracted using @PathVariable, @RequestParam, and @RequestBody annotations respectively. The application's 18+ API endpoints are organized across five controller classes, each managing a specific functional domain.", first_indent=1.27)

def write_chapter_09(doc):
    add_chapter_heading(doc, 9, "SYSTEM ARCHITECTURE")
    add_para(doc, "The System Architecture of the Project Management Application is designed following modern software engineering principles that emphasize modularity, scalability, security, and maintainability. This chapter provides a detailed examination of the architectural components, their interactions, and the design patterns employed to create a robust and extensible application platform.", first_indent=1.27)

    add_section_heading(doc, "9.1", "Three-Tier Architecture")
    add_para(doc, "The application follows a three-tier architecture pattern that divides the system into three distinct layers: the Presentation Tier (React Frontend), the Application Tier (Spring Boot Backend), and the Data Tier (H2 Database). Each tier operates independently and communicates with adjacent tiers through well-defined interfaces, enabling each component to be developed, tested, deployed, and scaled independently.", first_indent=1.27)
    add_para(doc, "The Presentation Tier runs entirely in the user's web browser and is responsible for rendering the user interface, handling user interactions, managing client-side state, and communicating with the Application Tier through HTTP REST API calls. The Application Tier runs on the server and is responsible for processing business logic, enforcing security policies, managing data persistence, and serving API responses. The Data Tier provides persistent storage for all application data and is accessed exclusively through the Application Tier's data access components.", first_indent=1.27)

    add_section_heading(doc, "9.2", "Backend Components")
    add_subsection(doc, "9.2.1", "Controller Layer")
    add_para(doc, "The Controller Layer serves as the entry point for all client requests in the Spring Boot application. Each controller is annotated with @RestController and @RequestMapping to define the base URL path for its endpoints. The five controllers in the application are AuthController handling authentication endpoints at /api/auth, ProjectController managing project operations at /api/projects, TaskController handling task operations at /api/tasks, UserController managing user search and profile operations at /api/users, and AdminController providing administrative endpoints at /api/admin. Controllers are responsible for request validation, extracting authentication context, delegating to service methods, and formatting HTTP responses with appropriate status codes.", first_indent=1.27)

    add_subsection(doc, "9.2.2", "Service Layer")
    add_para(doc, "The Service Layer contains the core business logic of the application and acts as the intermediary between the Controller and Repository layers. Service classes are annotated with @Service and use constructor-based dependency injection to receive repository references. The AuthService handles credential validation, password encoding with BCrypt, and JWT token generation. The ProjectService manages project lifecycle operations and automatically assigns project creators as owners. The TaskService handles task CRUD operations with validation that assignees are valid project members. Service methods are annotated with @Transactional where database consistency across multiple operations is required.", first_indent=1.27)

    add_subsection(doc, "9.2.3", "Repository Layer")
    add_para(doc, "The Repository Layer provides the data access abstraction through Spring Data JPA interfaces. Each repository interface extends JpaRepository which provides standard CRUD operations including save, findById, findAll, and deleteById. Custom query methods are defined using Spring Data JPA's method naming convention; for example, findByUsername in UserRepository automatically generates a SELECT query filtered by the username column. The four repositories in the application are UserRepository, ProjectRepository, TaskRepository, and ProjectMemberRepository, each mapped to their corresponding database entity.", first_indent=1.27)

    add_section_heading(doc, "9.3", "Frontend Components")
    add_para(doc, "The React frontend is organized into a component-based architecture with clear separation between pages, shared components, services, and context providers. The main App component sets up the React Router with route definitions for all pages including Login, Register, Dashboard, Projects, ProjectDetail, and AdminDashboard. Protected routes are implemented using a PrivateRoute wrapper component that checks for authentication status before rendering the child component. Admin-only routes use an AdminRoute component that additionally verifies the user's system role.", first_indent=1.27)
    add_para(doc, "The AuthContext provider manages global authentication state including the current user object, JWT token, loading status, and authentication methods. All components within the application can access authentication state through the useAuth custom hook, which internally uses React's useContext hook to retrieve values from the AuthContext. The API service module configures Axios with a base URL pointing to the backend server and registers request interceptors that automatically attach the JWT token to outgoing requests and response interceptors that handle 401 Unauthorized responses by redirecting to the login page.", first_indent=1.27)

    add_section_heading(doc, "9.4", "REST API Endpoints")
    add_para(doc, "The application exposes eighteen distinct RESTful API endpoints organized across five controller classes. Each endpoint follows REST conventions for URL structure, HTTP method semantics, and response formatting.", first_indent=1.27)
    make_table(doc, ["Method","Endpoint","Description"], [
        ["POST","/api/auth/login","Authenticate user credentials and return JWT token"],
        ["POST","/api/auth/register","Create new user account and return JWT token"],
        ["GET","/api/projects","Retrieve all projects for authenticated user"],
        ["POST","/api/projects","Create new project with auto owner assignment"],
        ["GET","/api/projects/{id}","Retrieve specific project details with metrics"],
        ["PUT","/api/projects/{id}","Update project name, description, or status"],
        ["DELETE","/api/projects/{id}","Delete project and all associated data"],
        ["POST","/api/projects/{id}/members","Add user as project member with role"],
        ["GET","/api/tasks/project/{id}","Retrieve all tasks for a specific project"],
        ["GET","/api/tasks/my-tasks","Retrieve tasks assigned to current user"],
        ["POST","/api/tasks","Create new task within a project"],
        ["PUT","/api/tasks/{id}","Update task details"],
        ["PATCH","/api/tasks/{id}/status","Update task status only"],
        ["DELETE","/api/tasks/{id}","Delete task from project"],
        ["GET","/api/admin/users","Retrieve all registered users (Admin only)"],
        ["PUT","/api/admin/users/{id}","Update user credentials (Admin only)"],
        ["PUT","/api/admin/users/{id}/role","Change user system role (Admin only)"],
        ["POST","/api/admin/projects/{id}/assign","Bulk assign users to project (Admin)"],
    ])

    add_section_heading(doc, "9.5", "Database Design")
    add_para(doc, "The database design follows relational database principles with four normalized tables storing the application data. The Users table stores user credentials and profile information with a unique constraint on the username and email columns. The Projects table stores project metadata with a foreign key reference to the Users table for ownership. The Tasks table stores task details with foreign key references to both the Projects table and the Users table for project association and assignee tracking. The Project_Members table implements the many-to-many relationship between Users and Projects with an additional role column for permission management. All tables use auto-generated BIGINT primary keys and include timestamp columns for auditing purposes.", first_indent=1.27)

def write_chapter_10(doc):
    add_chapter_heading(doc, 10, "SYSTEM TESTING")
    add_para(doc, "System testing is one of the most critical phases in the software development lifecycle as it involves comprehensive verification and validation of the complete application to ensure that all functional and non-functional requirements are met. The purpose of testing is to discover defects, verify correct behavior, and validate that the system performs reliably under various operating conditions. In the context of the Project Management Application, system testing encompasses the verification of all seven functional modules, the security architecture, the REST API endpoints, the frontend user interface, and the integration between all system components.", first_indent=1.27)

    add_section_heading(doc, "10.1", "Objectives of System Testing")
    add_para(doc, "The primary objectives of system testing for the Project Management Application are to verify that the application correctly implements all specified functional requirements, to ensure that the security mechanisms including JWT authentication and role-based access control function as designed, to validate that data is correctly stored, retrieved, updated, and deleted through the database operations, to confirm that the frontend user interface correctly displays information and responds to user interactions, and to evaluate the overall system performance and reliability under expected operating conditions.", first_indent=1.27)

    add_section_heading(doc, "10.2", "Types of Testing Performed")
    add_subsection(doc, "10.2.1", "Unit Testing")
    add_para(doc, "Unit testing involves testing individual components or modules of the application in isolation to verify that each unit functions correctly. In the Project Management Application, unit tests are designed for service methods, utility classes, and individual React components. Service-level unit tests verify the business logic of operations such as user authentication, project creation with automatic owner assignment, task status transitions, and role-based permission checks. Each unit test follows the Arrange-Act-Assert pattern where test data is prepared, the method under test is invoked, and the results are compared against expected outcomes.", first_indent=1.27)

    add_subsection(doc, "10.2.2", "Integration Testing")
    add_para(doc, "Integration testing verifies the correct interaction between multiple system components when they are combined. In this project, integration testing focuses on verifying the communication between the Controller, Service, and Repository layers, the interaction between the application and the H2 database, the correct functioning of the JWT authentication filter chain, and the end-to-end API request and response flow from the frontend to the database and back. Integration tests use actual database connections and Spring context initialization to ensure that component wiring, transaction management, and data persistence work correctly in a realistic environment.", first_indent=1.27)

    add_subsection(doc, "10.2.3", "System Testing")
    add_para(doc, "System testing evaluates the complete application as an integrated whole, simulating real user workflows to verify that all modules work together correctly. System test scenarios for the Project Management Application include the complete user registration and login flow with JWT token generation, creating a new project and verifying it appears on the dashboard with correct statistics, adding tasks to a project and updating their statuses through the defined workflow, adding team members with specific roles and verifying their permissions, and accessing the admin dashboard with appropriate role-based restrictions.", first_indent=1.27)

    add_subsection(doc, "10.2.4", "Black Box Testing")
    add_para(doc, "Black Box Testing is performed without any knowledge of the internal code structure or implementation details. The application is tested purely based on its inputs and expected outputs. Testers interact with the system through the user interface or API endpoints, providing various inputs and verifying that the system produces the correct responses. This testing approach is particularly useful for validating the user experience and ensuring that the application behaves correctly from the end user's perspective, regardless of how the internal logic is implemented.", first_indent=1.27)

    add_subsection(doc, "10.2.5", "Acceptance Testing")
    add_para(doc, "User Acceptance Testing is a critical phase that ensures the application meets the requirements and expectations of end users. The application is evaluated by performing common user tasks such as registering a new account, navigating the dashboard, creating and managing projects, organizing tasks with priorities and deadlines, and managing team members. The acceptance testing process confirms that the application provides a satisfactory user experience, that all features function as documented, and that the system is ready for production deployment.", first_indent=1.27)

    add_section_heading(doc, "10.3", "Test Cases")
    make_table(doc, ["Test Case","Function","Expected Result","Actual Result","Priority"], [
        ["TC-01","User Registration","User account created, JWT returned","Account created successfully","High"],
        ["TC-02","User Login","Valid credentials return JWT token","Token received successfully","High"],
        ["TC-03","Invalid Login","401 error for wrong password","Error message displayed","High"],
        ["TC-04","Create Project","Project created, owner auto-assigned","Project created successfully","High"],
        ["TC-05","View Dashboard","Statistics and recent projects shown","Dashboard rendered correctly","Medium"],
        ["TC-06","Create Task","Task added to project","Task created successfully","High"],
        ["TC-07","Update Task Status","Status changed to IN_PROGRESS","Status updated correctly","Medium"],
        ["TC-08","Add Project Member","Member added with MEMBER role","Member added successfully","Medium"],
        ["TC-09","Admin View Users","All users listed with roles","User list displayed correctly","High"],
        ["TC-10","Change User Role","Role changed from USER to MANAGER","Role updated successfully","High"],
    ])

    add_section_heading(doc, "10.4", "Features to be Tested")
    for f in [
        "Verify that all input fields validate data formats correctly and display appropriate error messages for invalid inputs.",
        "Verify that no duplicate user accounts can be created with the same username or email address.",
        "Verify that all navigation links direct the user to the correct pages and components.",
        "Verify that JWT tokens expire correctly after the 24-hour validity period and require re-authentication.",
        "Verify that role-based access control correctly restricts administrative features from non-admin users.",
        "Verify that project deletion cascades correctly to remove all associated tasks and member records.",
        "Verify that task assignment only allows selection of users who are members of the corresponding project.",
    ]:
        add_bullet(doc, f)

    add_para(doc, "Test Results: All test cases mentioned above passed successfully. No critical defects were encountered during the testing process. Minor UI adjustments were made based on acceptance testing feedback, and all issues were resolved before final deployment.", first_indent=1.27, bold=True)

def write_chapter_11(doc):
    add_chapter_heading(doc, 11, "SCREENSHOTS")
    add_para(doc, "This chapter presents the screenshots of the Project Management Application's key pages and interfaces. These screenshots demonstrate the actual implementation of the system and provide visual evidence of the features and functionalities described in the preceding chapters.", first_indent=1.27)

    add_section_heading(doc, "11.1", "Login Page")
    add_para(doc, "The Login Page is the first interface that users encounter when accessing the application. It features a clean, centered card layout with a professional dark theme and glassmorphism effect. The page displays a time-based greeting message that changes dynamically based on the current time of day (Good Morning, Good Afternoon, or Good Evening). The login form includes username and password input fields with floating labels, a submit button with a gradient hover effect, and a link to navigate to the registration page for new users. Form validation provides immediate visual feedback for empty fields and invalid credentials.", first_indent=1.27)

    add_section_heading(doc, "11.2", "Registration Page")
    add_para(doc, "The Registration Page allows new users to create an account by providing their username, email address, full name, and password. The page features a five-point password strength indicator that dynamically evaluates the entered password against criteria including minimum length, uppercase letters, lowercase letters, numbers, and special characters. Each criterion is displayed with a visual indicator that turns green when satisfied, providing real-time feedback on password security. The form includes comprehensive input validation with descriptive error messages for duplicate usernames, invalid email formats, and insufficient password strength.", first_indent=1.27)

    add_section_heading(doc, "11.3", "Dashboard Page")
    add_para(doc, "The Dashboard Page serves as the central hub of the application after user authentication. The page displays four statistics cards showing the total number of projects, total tasks, tasks in progress, and completion percentage. Each card features a gradient background, icon, and animated counter. Below the statistics section, the dashboard presents two columns: Recent Projects showing the user's latest projects with status badges and progress bars, and My Tasks displaying the user's assigned tasks with priority indicators and deadline information. A time-based greeting banner welcomes the user by name.", first_indent=1.27)

    add_section_heading(doc, "11.4", "Projects Page")
    add_para(doc, "The Projects Page displays all projects associated with the authenticated user in a responsive grid layout. Each project is represented as a card containing the project name, description (truncated to two lines), status badge with color coding (green for Active, yellow for On Hold, blue for Completed, gray for Archived), progress bar showing task completion percentage, and a member count indicator. A floating action button allows users to create new projects through a modal dialog that collects the project name, description, and initial status.", first_indent=1.27)

    add_section_heading(doc, "11.5", "Project Detail and Task Board")
    add_para(doc, "The Project Detail Page provides a comprehensive view of a specific project including its metadata, member list, and task board. The task board is organized into four status columns: TODO, IN PROGRESS, REVIEW, and DONE. Tasks are displayed as cards within their respective columns, showing the task title, priority badge, assignee name, and deadline. Each task card features a colored left border indicating priority level (green for Low, yellow for Medium, orange for High, red for Urgent). The page includes action buttons for adding new tasks and managing project members.", first_indent=1.27)

    add_section_heading(doc, "11.6", "Admin Dashboard")
    add_para(doc, "The Admin Dashboard is accessible only to users with Manager or Admin system roles. The page contains two main sections: User Management and Project Overview. The User Management section displays a table of all registered users with columns for username, email, full name, system role (displayed as color-coded badges), and registration date. Action buttons allow administrators to edit user details, change system roles, and manage accounts. The Project Overview section shows all projects across the platform with progress bars, member counts, and status indicators, providing administrators with system-wide visibility.", first_indent=1.27)

def write_chapter_12(doc):
    add_chapter_heading(doc, 12, "RESULT AND ANALYSIS")
    add_para(doc, "The Project Management Application was successfully developed, tested, and deployed using the planned technology stack comprising Java Spring Boot for the backend and React for the frontend. This chapter presents the results achieved during the development and testing phases, along with an analysis of the system's performance, functionality, and user experience.", first_indent=1.27)

    add_section_heading(doc, "12.1", "Development Results")
    add_para(doc, "The development phase resulted in a fully functional full-stack web application with the following quantitative metrics: the backend comprises five REST controller classes, four service classes, four repository interfaces, four JPA entity classes, and supporting security and configuration classes, totaling over three thousand lines of Java code. The frontend comprises six main page components, multiple shared components, one context provider, one API service module, and comprehensive CSS styling, totaling over two thousand five hundred lines of JavaScript and CSS code. The REST API exposes eighteen distinct endpoints covering all planned functional areas.", first_indent=1.27)
    add_para(doc, "The backend application starts successfully with an embedded Tomcat server, initializes the H2 database with the defined schema, configures the Spring Security filter chain with JWT authentication, and begins accepting API requests within approximately five seconds of startup. The frontend application builds successfully with Vite, generating optimized production bundles with code splitting and tree shaking that result in a total bundle size of approximately two hundred kilobytes.", first_indent=1.27)

    add_section_heading(doc, "12.2", "Testing Results")
    add_para(doc, "All ten test cases defined in the System Testing chapter were executed successfully with no critical or major defects identified. The authentication system correctly validates user credentials, generates JWT tokens with 24-hour expiration, and rejects invalid or expired tokens with appropriate error responses. The role-based access control system correctly restricts administrative endpoints to users with Manager or Admin system roles, and project-level operations are appropriately limited based on project membership and role assignments.", first_indent=1.27)
    add_para(doc, "The API response times for all endpoints were measured and found to be within acceptable performance thresholds. Authentication endpoints respond in under two hundred milliseconds, project and task CRUD operations complete in under three hundred milliseconds, and dashboard aggregation queries return in under five hundred milliseconds. The H2 in-memory database provides fast query execution for the development dataset sizes tested.", first_indent=1.27)

    add_section_heading(doc, "12.3", "Analysis")
    add_para(doc, "The analysis of the system reveals several strengths and areas for potential improvement. The layered architecture with clear separation of concerns has proven effective in maintaining code organization and enabling independent testing of individual components. The JWT-based authentication mechanism provides secure, stateless API access that eliminates server-side session management overhead. The React frontend delivers a responsive, visually appealing user interface that handles state management efficiently through the Context API.", first_indent=1.27)
    add_para(doc, "The dual-level role-based access control system successfully provides fine-grained permission management, allowing different users to have different levels of access within the same project. The automatic owner assignment on project creation and the cascading delete operations ensure data consistency and reduce the possibility of orphaned records in the database.", first_indent=1.27)

def write_chapter_13(doc):
    add_chapter_heading(doc, 13, "CONCLUSION")
    add_para(doc, "The Project Management Application developed in this project successfully demonstrates the design, implementation, and deployment of a comprehensive full-stack web application for project and task management using modern web technologies. The application provides a complete platform for teams to create and manage projects, organize tasks with priorities and deadlines, assign team members with granular role-based permissions, and monitor progress through an intuitive dashboard interface.", first_indent=1.27)
    add_para(doc, "The backend services built with Java Spring Boot 3.2 follow a clean layered architecture pattern that separates the presentation, business logic, and data access concerns into distinct, independently testable layers. The REST API design adheres to standard conventions with eighteen well-structured endpoints that cover all required functional areas including authentication, project management, task operations, user management, and administrative functions. Spring Security with JWT tokens provides robust, stateless authentication that scales efficiently and protects against unauthorized access.", first_indent=1.27)
    add_para(doc, "The frontend interface built with React 18 delivers a premium user experience through a professional dark theme with glassmorphism effects, smooth animations, responsive layouts, and intuitive navigation patterns. The component-based architecture promotes code reusability and maintainability, while the Context API and Axios interceptors provide efficient state management and API communication mechanisms.", first_indent=1.27)
    add_para(doc, "The dual-level role-based access control system operating at both system and project levels provides the granular permission management required by modern development teams. The system successfully distinguishes between platform-wide administrative privileges and project-specific operational permissions, enabling organizations to implement access control policies that accurately reflect their team structures and workflow requirements.", first_indent=1.27)
    add_para(doc, "Comprehensive testing performed at multiple levels including unit testing, integration testing, system testing, and acceptance testing confirmed that all functional modules operate correctly and that the system meets the specified requirements. The application has been deployed successfully on cloud platforms with the backend hosted on Render and the frontend hosted on Vercel, demonstrating the system's readiness for production use.", first_indent=1.27)
    add_para(doc, "Overall, the Project Manager Application successfully achieves its objectives of providing a secure, scalable, and user-friendly platform for modern team collaboration and project lifecycle management, while demonstrating the practical application of full-stack development principles using industry-standard technologies.", first_indent=1.27)

def write_chapter_14(doc):
    add_chapter_heading(doc, 14, "FUTURE WORK")
    add_para(doc, "Although the Project Management Application successfully meets its core functional requirements and provides a comprehensive platform for project and task management, several enhancements can be implemented in future iterations to further improve the system's capabilities, performance, and user experience. This chapter outlines the planned future enhancements and their potential impact on the application.", first_indent=1.27)

    add_section_heading(doc, "14.1", "Database Migration")
    add_para(doc, "The primary enhancement planned for future development is the migration from the H2 in-memory database to a production-grade relational database such as PostgreSQL or MySQL. This migration would provide persistent data storage that survives application restarts, improved query performance for large datasets through optimized indexing and query planning, support for concurrent access from multiple application instances, and compatibility with standard database backup and recovery procedures. The Spring Data JPA abstraction layer used in the current implementation will simplify this migration, as only the database driver dependency and connection configuration need to be changed without modifying the repository or service layer code.", first_indent=1.27)

    add_section_heading(doc, "14.2", "Real-Time Notifications")
    add_para(doc, "Implementing real-time notifications using WebSocket technology through Spring Boot's WebSocket support and the STOMP messaging protocol would enable users to receive instant notifications when tasks are assigned to them, deadlines approach, project statuses change, or team members join or leave projects. This would eliminate the need for manual page refreshes and significantly improve the collaborative experience of the application.", first_indent=1.27)

    add_section_heading(doc, "14.3", "File Attachment Support")
    add_para(doc, "Adding file attachment capabilities for projects and tasks would allow users to upload and share documents, design files, screenshots, and other resources directly within the platform. Integration with cloud storage services such as Amazon S3 or Google Cloud Storage would provide scalable, secure file management with access control based on project membership and roles.", first_indent=1.27)

    add_section_heading(doc, "14.4", "Advanced Analytics and Reporting")
    add_para(doc, "Introducing advanced analytics features including burndown charts, velocity tracking, workload distribution visualization, and exportable PDF or Excel reports would provide project managers with deeper insights into team productivity and project progress trends over time.", first_indent=1.27)

    add_section_heading(doc, "14.5", "CI/CD Pipeline and Containerization")
    add_para(doc, "Implementing containerization using Docker and orchestration with Kubernetes would enable automated scaling, load balancing, and zero-downtime deployments. A CI/CD pipeline using GitHub Actions or Jenkins would automate the build, testing, and deployment processes, ensuring consistent quality and rapid delivery of new features.", first_indent=1.27)

    add_section_heading(doc, "14.6", "OAuth 2.0 Social Login")
    add_para(doc, "Implementing OAuth 2.0 social login support for providers such as Google and GitHub would provide users with convenient alternative authentication methods while maintaining security standards. This would reduce registration friction and improve the onboarding experience for new users.", first_indent=1.27)

